"use client";
import { AnimatedTooltip } from "@/components/ui/animated-tooltip";

export default function PlacedTooltips() {
  const btn = "rounded-md bg-neutral-800 px-4 py-2 text-sm text-white";
  return (
    <div className="grid grid-cols-2 gap-6 p-16">
      <AnimatedTooltip content="Top" side="top"><button className={btn}>Top</button></AnimatedTooltip>
      <AnimatedTooltip content="Right" side="right"><button className={btn}>Right</button></AnimatedTooltip>
      <AnimatedTooltip content="Bottom" side="bottom"><button className={btn}>Bottom</button></AnimatedTooltip>
      <AnimatedTooltip content="Left" side="left"><button className={btn}>Left</button></AnimatedTooltip>
    </div>
  );
}

"use client";
import { AnimatedTooltip } from "@/components/ui/animated-tooltip";

export default function MinimalTooltip() {
  return (
    <div className="flex items-center justify-center p-16">
      <AnimatedTooltip content="Instant, arrowless label" arrow={false} delay={0} offset={6}>
        <button className="rounded-md bg-neutral-800 px-4 py-2 text-sm text-white">
          Hover me
        </button>
      </AnimatedTooltip>
    </div>
  );
}

"use client";
import { AnimatedTooltip } from "@/components/ui/animated-tooltip";

export default function RichTooltip() {
  return (
    <div className="flex items-center justify-center p-16">
      <AnimatedTooltip
        side="bottom"
        className="max-w-[16rem]"
        background="#0f172a"
        color="#e2e8f0"
        content={
          <div className="space-y-1">
            <p className="font-semibold">Keyboard shortcut</p>
            <p className="text-xs text-slate-400">
              Press {"\u2318"}K to open the command palette from anywhere.
            </p>
          </div>
        }
      >
        <button className="rounded-md bg-slate-800 px-4 py-2 text-sm text-white">
          Command palette
        </button>
      </AnimatedTooltip>
    </div>
  );
}

"use client";
import { AnimatedTooltip } from "@/components/ui/animated-tooltip";
import { Info } from "lucide-react";

export default function TriggerVariants() {
  return (
    <div className="flex items-center justify-center gap-8 p-16">
      <AnimatedTooltip content="More information" side="top">
        <button
          aria-label="More information"
          className="grid h-9 w-9 place-items-center rounded-full bg-neutral-800 text-white"
        >
          <Info className="h-4 w-4" />
        </button>
      </AnimatedTooltip>

      <AnimatedTooltip content="Opens in a new tab" side="top">
        <a
          href="https://example.com"
          className="text-sm font-medium text-violet-500 underline underline-offset-4"
        >
          Documentation
        </a>
      </AnimatedTooltip>
    </div>
  );
}
